INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a0b6f6e5-032e-4d27-af61-d775331b9a52',
  '00000000-0000-0000-0000-000000000001',
  $escape$Arduino: Mastering Analog and Digital I/O with Sensors and Actuators$escape$,
  $escape$When reading analog sensors, use `analogRead()` to convert ADC values to voltage, and `map()` to linearly scale values. For digital sensors, employ `digitalRead()` and `pinMode()` to set input modes. To drive actuators, utilize `analogWrite()` for PWM outputs and `digitalWrite()` for digital outputs. The choice between `I2C`, `SPI`, and `UART` protocols depends on the sensor or actuator's requirements. For instance, use `Wire` for I2C communication.$escape$,
  $escape${'code': ['const int sensorPin = A0;', 'const int ledPin = 9;', 'void setup() {', '  pinMode(ledPin, OUTPUT);', '}', 'void loop() {', '  int sensorValue = analogRead(sensorPin);', '  int ledValue = map(sensorValue, 0, 1023, 0, 255);', '  analogWrite(ledPin, ledValue);', '  delay(100);', '}'], 'language': 'cpp'}$escape$,
  $escape$cpp$escape$,
