INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e6f944fe-41ec-4bfe-a317-4e4430d7aaa7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Arduino vs ESP32 vs Raspberry Pi vs STM32: Choosing the Right Microcontroller for Your Project$escape$,
  $escape$When selecting a microcontroller for your Arduino project, consider factors like processing power, memory, and I/O capabilities. Arduino boards offer a range of options, but you may need more power or specific features. ESP32 combines Wi-Fi and Bluetooth capabilities, while Raspberry Pi provides a Linux-based OS. STM32 series offer high-performance and large Flash memory. Evaluate your project's requirements and choose the board that best fits. For instance, if you need Wi-Fi and BLE connectivity, ESP32 might be the best choice.$escape$,
  NULL,
  NULL,
